 * This test ensures that properties and functions with multiline strings are treated consistently.
 */
internal class IndentationRuleMultilineStringTest {
    private val indentationRuleAssertThat = assertThatRule { IndentationRule() }

    @Test
    fun `Given a function with expression body returning multiline string, closing quotes should have proper indentation`() {
        val code =
            """
            fun foo() = $MULTILINE_STRING_QUOTE
                <!--suppress XmlUnusedNamespaceDeclaration -->
                <manifest xmlns:android="http://schemas.android.com/apk/res/android"/>
                $MULTILINE_STRING_QUOTE.trimIndent()
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a function with block body returning multiline string, closing quotes should have proper indentation`() {
        val code =
            """
            fun foo2(): String {
                return $MULTILINE_STRING_QUOTE
                    <!--suppress XmlUnusedNamespaceDeclaration -->
                    <manifest xmlns:android="http://schemas.android.com/apk/res/android"/>
                    $MULTILINE_STRING_QUOTE.trimIndent()
            }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a property with multiline string, closing quotes should have proper indentation like function expression body`() {
        val code =
            """
            val foo = $MULTILINE_STRING_QUOTE
                <!--suppress XmlUnusedNamespaceDeclaration -->
                <manifest xmlns:android="http://schemas.android.com/apk/res/android"/>
                $MULTILINE_STRING_QUOTE.trimIndent()
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given all three cases together, they should all be treated consistently`() {
        val code =
            """
            fun foo() = $MULTILINE_STRING_QUOTE
                <!--suppress XmlUnusedNamespaceDeclaration -->
                <manifest xmlns:android="http://schemas.android.com/apk/res/android"/>
                $MULTILINE_STRING_QUOTE.trimIndent()

            fun foo2(): String {
                return $MULTILINE_STRING_QUOTE
                    <!--suppress XmlUnusedNamespaceDeclaration -->
                    <manifest xmlns:android="http://schemas.android.com/apk/res/android"/>
                    $MULTILINE_STRING_QUOTE.trimIndent()
            }

            val foo3 = $MULTILINE_STRING_QUOTE
                <!--suppress XmlUnusedNamespaceDeclaration -->
                <manifest xmlns:android="http://schemas.android.com/apk/res/android"/>
                $MULTILINE_STRING_QUOTE.trimIndent()
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

    @Test
    fun `Given a property inside a class with multiline string`() {
        val code =
            """
            class Foo {
                val bar = $MULTILINE_STRING_QUOTE
                    some text
                    $MULTILINE_STRING_QUOTE.trimIndent()
            }
            """.trimIndent()
        indentationRuleAssertThat(code).hasNoLintViolations()
    }

